                // r について昇順で並んでいるので、 c を比べて判定

                if(rc[i].second < rc[k].second) continue;



                int N = rc[i].first + rc[i].second - rc[k].first - rc[k].second;

                int K = rc[i].first - rc[k].first;

                // (r_k, c_k) から (r_i, c_i) に到達する経路数

