modint dp[3005][2];



int main(){

    ios::sync_with_stdio(false);

    cin.tie(nullptr);



    int h, w, n;

    cin >> h >> w >> n;

    vector<Data> input(n);

    for(int i = 0; i < n; ++i)  cin >> input[i];

    input.push_back(Data(1, 1));

    sort(input.begin(), input.end());

    Combination<modint> comb(h + w + 5);



    dp[0][0] = 1;

    for(int i = 1; i <= n; ++i){

        int nr = input[i].r, nc = input[i].c;

        for(int j = 0; j < i; ++j){

            int r = input[j].r, c = input[j].c;

            if(nc - c < 0)  continue;

            modint route = comb.get_combination(nr - r + nc - c, nr - r);

            for(int k = 0; k < 2; ++k){

                if(dp[j][k] == 0)   continue;

                dp[i][k ^ 1] += dp[j][k] * route;

            }

        }

    }



    modint ban = 0;

    for(int i = 1; i <= n; ++i){

        int r = input[i].r, c = input[i].c;

        modint route = comb.get_combination(h - r + w - c, h - r);

        ban -= dp[i][0] * route;

        ban += dp[i][1] * route;

    }



    modint ans = comb.get_combination(h + w - 2, h - 1) - ban;

    cout << ans << endl;

}

